/**
 * @fileoverview Additional tests for ResetSettingsAction targeting surviving mutants.
 */

import { describe, it, expect, vi, beforeEach } from 'vitest';
import * as vscode from 'vscode';
import { ResetSettingsAction } from '../../../src/extension/actions/resetSettings';
import type { ISettingsSnapshot } from '../../../src/shared/settings/snapshot';

vi.mock('vscode', () => ({
  workspace: {
    getConfiguration: vi.fn(),
  },
  ConfigurationTarget: {
    Global: 1,
    Workspace: 2,
    WorkspaceFolder: 3,
  },
}));

function createMockConfig(store: Record<string, unknown>) {
  return {
    get: vi.fn(<T>(key: string, defaultValue?: T): T => {
      return (key in store ? store[key] : defaultValue) as T;
    }),
    update: vi.fn(async (key: string, value: unknown) => {
      if (value === undefined) {
        delete store[key];
      } else {
        store[key] = value;
      }
    }),
  } as unknown as vscode.WorkspaceConfiguration;
}

function createMockContext() {
  const state: Record<string, unknown> = {};
  return {
    workspaceState: {
      get: vi.fn(<T>(key: string, defaultValue?: T): T => {
        return (key in state ? state[key] : defaultValue) as T;
      }),
      update: vi.fn(async (key: string, value: unknown) => {
        state[key] = value;
      }),
    },
    _state: state,
  } as unknown as vscode.ExtensionContext & { _state: Record<string, unknown> };
}

describe('ResetSettingsAction (extra mutant coverage)', () => {
  let settingsStore: Record<string, unknown>;

  const SNAPSHOT: ISettingsSnapshot = {
    physics: { repelForce: 10, linkDistance: 100, linkForce: 0.2, damping: 0.5, centerForce: 0.3 },
    legends: [],
    filterPatterns: [],
    showOrphans: true,
    bidirectionalMode: 'separate',
    directionMode: 'arrows',
    directionColor: '#000000',
    nodeColors: { file: '#999999', folder: '#888888' },
    nodeVisibility: { file: true, folder: true },
    edgeVisibility: { imports: true, nests: false },
    edgeColors: { imports: '#777777', nests: '#666666' },
    pluginOrder: ['codegraphy.markdown', 'codegraphy.python'],
    disabledPlugins: ['codegraphy.python'],
    particleSpeed: 0.001,
    particleSize: 4,
    showLabels: true,
    maxFiles: 500,
    nodeSizeMode: 'connections',
  };

  beforeEach(() => {
    vi.clearAllMocks();
    settingsStore = {
      'physics.repelForce': SNAPSHOT.physics.repelForce,
      'physics.linkDistance': SNAPSHOT.physics.linkDistance,
      'physics.linkForce': SNAPSHOT.physics.linkForce,
      'physics.damping': SNAPSHOT.physics.damping,
      'physics.centerForce': SNAPSHOT.physics.centerForce,
      legend: [],
      filterPatterns: [],
      showOrphans: true,
      bidirectionalEdges: 'separate',
      directionMode: 'arrows',
      directionColor: '#000000',
      nodeColors: { file: '#999999', folder: '#888888' },
      nodeVisibility: { file: true, folder: true },
      edgeVisibility: { imports: true, nests: false },
      edgeColors: { imports: '#777777', nests: '#666666' },
      pluginOrder: ['codegraphy.markdown', 'codegraphy.python'],
      disabledPlugins: ['codegraphy.python'],
      particleSpeed: 0.001,
      particleSize: 4,
      showLabels: true,
      maxFiles: 500,
      nodeSizeMode: 'file-size',
    };
  });

  it('resets all five physics keys to undefined during execute', async () => {
    const mockConfig = createMockConfig(settingsStore);
    vi.mocked(vscode.workspace.getConfiguration).mockReturnValue(mockConfig);

    const ctx = createMockContext();
    const action = new ResetSettingsAction(
      SNAPSHOT,
      vscode.ConfigurationTarget.Workspace,
      ctx,
      vi.fn(),
      vi.fn(),
      vi.fn().mockResolvedValue(undefined),
    );

    await action.execute();

    const physicsUpdateCalls = (mockConfig.update as ReturnType<typeof vi.fn>).mock.calls
      .filter(([key]) => String(key).startsWith('physics.'));
    const updatedKeys = physicsUpdateCalls.map((call) => call[0]);
    expect(updatedKeys).toContain('physics.repelForce');
    expect(updatedKeys).toContain('physics.linkDistance');
    expect(updatedKeys).toContain('physics.linkForce');
    expect(updatedKeys).toContain('physics.damping');
    expect(updatedKeys).toContain('physics.centerForce');

    // All values should be undefined
    for (const call of physicsUpdateCalls) {
      expect(call[1]).toBeUndefined();
    }
  });

  it('resets all CONFIG_TO_SNAPSHOT config keys to undefined during execute', async () => {
    const mockConfig = createMockConfig(settingsStore);
    vi.mocked(vscode.workspace.getConfiguration).mockReturnValue(mockConfig);

    const ctx = createMockContext();
    const action = new ResetSettingsAction(
      SNAPSHOT,
      vscode.ConfigurationTarget.Workspace,
      ctx,
      vi.fn(),
      vi.fn(),
      vi.fn().mockResolvedValue(undefined),
    );

    await action.execute();

    const cgUpdateCalls = (mockConfig.update as ReturnType<typeof vi.fn>).mock.calls
      .filter(([key]) => !String(key).startsWith('physics.'));
    const updatedKeys = cgUpdateCalls.map((call) => call[0]);
    expect(updatedKeys).toContain('legend');
    expect(updatedKeys).toContain('filterPatterns');
    expect(updatedKeys).toContain('showOrphans');
    expect(updatedKeys).toContain('bidirectionalEdges');
    expect(updatedKeys).toContain('directionMode');
    expect(updatedKeys).toContain('directionColor');
    expect(updatedKeys).toContain('nodeColors');
    expect(updatedKeys).toContain('nodeVisibility');
    expect(updatedKeys).toContain('edgeVisibility');
    expect(updatedKeys).toContain('edgeColors');
    expect(updatedKeys).toContain('pluginOrder');
    expect(updatedKeys).toContain('disabledPlugins');
    expect(updatedKeys).toContain('particleSpeed');
    expect(updatedKeys).toContain('particleSize');
    expect(updatedKeys).toContain('showLabels');
    expect(updatedKeys).toContain('maxFiles');
    expect(updatedKeys).toContain('nodeSizeMode');

    for (const call of cgUpdateCalls) {
      if (call[0] === 'nodeSizeMode') {
        expect(call[1]).toBe('connections');
        continue;
      }

      expect(call[1]).toBeUndefined();
    }
  });

  it('undo restores each physics key to its original value', async () => {
    const originalPhysics = { repelForce: 10, linkDistance: 100, linkForce: 0.2, damping: 0.5, centerForce: 0.3 };
    const mockConfig = createMockConfig({ ...settingsStore });
    vi.mocked(vscode.workspace.getConfiguration).mockReturnValue(mockConfig);

    const ctx = createMockContext();
    const action = new ResetSettingsAction(
      SNAPSHOT,
      vscode.ConfigurationTarget.Workspace,
      ctx,
      vi.fn(),
      vi.fn(),
      vi.fn().mockResolvedValue(undefined),
    );

    await action.execute();
    vi.clearAllMocks();
    vi.mocked(vscode.workspace.getConfiguration).mockReturnValue(mockConfig);

    await action.undo();

    const physicsUpdateCalls = (mockConfig.update as ReturnType<typeof vi.fn>).mock.calls
      .filter(([key]) => String(key).startsWith('physics.'));
    for (const call of physicsUpdateCalls) {
      const key = String(call[0]).replace('physics.', '') as keyof typeof originalPhysics;
      expect(call[1]).toBe(originalPhysics[key]);
    }

    const nonPhysicsUpdateCalls = (mockConfig.update as ReturnType<typeof vi.fn>).mock.calls
      .filter(([key]) => !String(key).startsWith('physics.'));
    expect(nonPhysicsUpdateCalls.some(([key, value]) => key === 'nodeColors' && value === SNAPSHOT.nodeColors)).toBe(true);
    expect(nonPhysicsUpdateCalls.some(([key, value]) => key === 'nodeVisibility' && value === SNAPSHOT.nodeVisibility)).toBe(true);
    expect(nonPhysicsUpdateCalls.some(([key, value]) => key === 'edgeVisibility' && value === SNAPSHOT.edgeVisibility)).toBe(true);
    expect(nonPhysicsUpdateCalls.some(([key, value]) => key === 'edgeColors' && value === SNAPSHOT.edgeColors)).toBe(true);
    expect(nonPhysicsUpdateCalls.some(([key, value]) => key === 'pluginOrder' && value === SNAPSHOT.pluginOrder)).toBe(true);
    expect(nonPhysicsUpdateCalls.some(([key, value]) => key === 'disabledPlugins' && value === SNAPSHOT.disabledPlugins)).toBe(true);
  });

  it('updates repo settings without a VS Code config target argument', async () => {
    const mockConfig = createMockConfig({ ...settingsStore });
    vi.mocked(vscode.workspace.getConfiguration).mockReturnValue(mockConfig);

    const ctx = createMockContext();
    const action = new ResetSettingsAction(
      SNAPSHOT,
      vscode.ConfigurationTarget.Global,
      ctx,
      vi.fn(),
      vi.fn(),
      vi.fn().mockResolvedValue(undefined),
    );

    await action.execute();

    const physicsUpdateCalls = (mockConfig.update as ReturnType<typeof vi.fn>).mock.calls
      .filter(([key]) => String(key).startsWith('physics.'));
    for (const call of physicsUpdateCalls) {
      expect(call[2]).toBeUndefined();
    }
  });
});

/**
 * @fileoverview Tests for ResetSettingsAction.
 */

import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import * as vscode from 'vscode';
import { ResetSettingsAction } from '../../../src/extension/actions/resetSettings';
import { getUndoManager, resetUndoManager } from '../../../src/extension/undoManager';
import type { ISettingsSnapshot } from '../../../src/shared/settings/snapshot';

vi.mock('vscode', () => ({
  workspace: {
    getConfiguration: vi.fn(),
  },
  ConfigurationTarget: {
    Global: 1,
    Workspace: 2,
    WorkspaceFolder: 3,
  },
}));

/** Build a mock WorkspaceConfiguration that stores values in a plain object. */
function createMockConfig(store: Record<string, unknown>) {
  const get = vi.fn(<T>(key: string, defaultValue?: T): T => {
    return (key in store ? store[key] : defaultValue) as T;
  });
  const update = vi.fn(async (key: string, value: unknown) => {
    if (value === undefined) {
      delete store[key];
    } else {
      store[key] = value;
    }
  });
  const inspect = vi.fn(() => ({ workspaceValue: undefined }));
  return { get, update, inspect } as unknown as vscode.WorkspaceConfiguration;
}

/** Build a mock ExtensionContext with workspaceState. */
function createMockContext() {
  const state: Record<string, unknown> = {};
  return {
    workspaceState: {
      get: vi.fn(<T>(key: string, defaultValue?: T): T => {
        return (key in state ? state[key] : defaultValue) as T;
      }),
      update: vi.fn(async (key: string, value: unknown) => {
        state[key] = value;
      }),
    },
    _state: state,
  } as unknown as vscode.ExtensionContext & { _state: Record<string, unknown> };
}

describe('ResetSettingsAction', () => {
  let settingsStore: Record<string, unknown>;
  let mockConfig: vscode.WorkspaceConfiguration;
  let mockSendAllSettings: ReturnType<typeof vi.fn>;
  let mockSetNodeSizeMode: ReturnType<typeof vi.fn>;
  let mockRefreshGraph: ReturnType<typeof vi.fn>;
  let mockContext: vscode.ExtensionContext & { _state: Record<string, unknown> };

  const NON_DEFAULT_SNAPSHOT: ISettingsSnapshot = {
    physics: { repelForce: 5, linkDistance: 200, linkForce: 0.5, damping: 0.3, centerForce: 0.5 },
    legends: [{ id: 'g1', pattern: '*.ts', color: '#FF0000' }],
    filterPatterns: ['**/*.test.ts'],
    showOrphans: false,
    bidirectionalMode: 'combined',
    directionMode: 'particles',
    directionColor: '#FF0000',
    nodeColors: { file: '#111111', folder: '#222222' },
    nodeVisibility: { file: true, folder: false },
    edgeVisibility: { imports: true, calls: false },
    edgeColors: { imports: '#333333', calls: '#444444' },
    pluginOrder: ['codegraphy.markdown', 'codegraphy.typescript'],
    disabledPlugins: ['codegraphy.python'],
    particleSpeed: 0.002,
    particleSize: 8,
    showLabels: false,
    maxFiles: 1000,
    nodeSizeMode: 'file-size',
  };

  function wireConfigMocks() {
    vi.mocked(vscode.workspace.getConfiguration).mockReturnValue(mockConfig);
  }

  function createAction() {
    return new ResetSettingsAction(
      NON_DEFAULT_SNAPSHOT,
      vscode.ConfigurationTarget.Workspace,
      mockContext,
      mockSendAllSettings,
      mockSetNodeSizeMode,
      mockRefreshGraph,
    );
  }

  beforeEach(() => {
    vi.clearAllMocks();
    resetUndoManager();

    settingsStore = {
      'physics.repelForce': 5,
      'physics.linkDistance': 200,
      'physics.linkForce': 0.5,
      'physics.damping': 0.3,
      'physics.centerForce': 0.5,
      legend: [{ id: 'g1', pattern: '*.ts', color: '#FF0000' }],
      filterPatterns: ['**/*.test.ts'],
      showOrphans: false,
      bidirectionalEdges: 'combined',
      directionMode: 'particles',
      directionColor: '#FF0000',
      nodeColors: { file: '#111111', folder: '#222222' },
      nodeVisibility: { file: true, folder: false },
      edgeVisibility: { imports: true, calls: false },
      edgeColors: { imports: '#333333', calls: '#444444' },
      pluginOrder: ['codegraphy.markdown', 'codegraphy.typescript'],
      disabledPlugins: ['codegraphy.python'],
      particleSpeed: 0.002,
      particleSize: 8,
      showLabels: false,
      maxFiles: 1000,
      nodeSizeMode: 'file-size',
    };

    mockConfig = createMockConfig(settingsStore);
    wireConfigMocks();

    mockContext = createMockContext();
    mockSendAllSettings = vi.fn();
    mockSetNodeSizeMode = vi.fn();
    mockRefreshGraph = vi.fn().mockResolvedValue(undefined);
  });

  afterEach(() => {
    vi.clearAllMocks();
  });

  it('has descriptive description', () => {
    expect(createAction().description).toBe('Reset all settings');
  });

  it('execute resets config keys and sets nodeSizeMode to connections', async () => {
    await createAction().execute();

    const updateCalls = (mockConfig.update as ReturnType<typeof vi.fn>).mock.calls;

    for (const call of updateCalls.filter(([key]) => String(key).startsWith('physics.'))) {
      expect(call[1]).toBeUndefined();
    }

    for (const call of updateCalls.filter(([key]) => String(key) === 'nodeSizeMode')) {
      expect(call[1]).toBe('connections');
    }
    for (const call of updateCalls.filter(([key]) => !String(key).startsWith('physics.') && String(key) !== 'nodeSizeMode')) {
      expect(call[1]).toBeUndefined();
    }

    expect(settingsStore.legend).toBeUndefined();
    expect(settingsStore.nodeSizeMode).toBe('connections');
    expect(Object.keys(settingsStore)).toEqual(['nodeSizeMode']);
  });

  it('execute resets nodeSizeMode to connections and refreshes graph', async () => {
    await createAction().execute();

    expect(mockSetNodeSizeMode).toHaveBeenCalledWith('connections');
    expect(mockSendAllSettings).toHaveBeenCalled();
    expect(mockRefreshGraph).toHaveBeenCalled();
  });

  it('undo restores all captured config values', async () => {
    const action = createAction();
    await action.execute();

    expect(settingsStore.legend).toBeUndefined();
    expect(settingsStore.nodeSizeMode).toBe('connections');
    expect(Object.keys(settingsStore)).toEqual(['nodeSizeMode']);

    vi.clearAllMocks();
    wireConfigMocks();
    await action.undo();

    expect(settingsStore['physics.repelForce']).toBe(5);
    expect(settingsStore['physics.linkDistance']).toBe(200);
    expect(settingsStore['physics.linkForce']).toBe(0.5);
    expect(settingsStore['physics.damping']).toBe(0.3);
    expect(settingsStore['physics.centerForce']).toBe(0.5);
    expect(settingsStore.legend).toEqual([{ id: 'g1', pattern: '*.ts', color: '#FF0000' }]);
    expect(settingsStore.showOrphans).toBe(false);
    expect(settingsStore.directionMode).toBe('particles');
    expect(settingsStore.nodeColors).toEqual({ file: '#111111', folder: '#222222' });
    expect(settingsStore.nodeVisibility).toEqual({ file: true, folder: false });
    expect(settingsStore.edgeVisibility).toEqual({ imports: true, calls: false });
    expect(settingsStore.edgeColors).toEqual({ imports: '#333333', calls: '#444444' });
    expect(settingsStore.pluginOrder).toEqual(['codegraphy.markdown', 'codegraphy.typescript']);
    expect(settingsStore.disabledPlugins).toEqual(['codegraphy.python']);
    expect(settingsStore.maxFiles).toBe(1000);
    expect(settingsStore.bidirectionalEdges).toBe('combined');
    expect(settingsStore.nodeSizeMode).toBe('file-size');
  });

  it('undo restores original nodeSizeMode and refreshes graph', async () => {
    const action = createAction();
    await action.execute();
    vi.clearAllMocks();
    wireConfigMocks();

    await action.undo();

    expect(mockSetNodeSizeMode).toHaveBeenCalledWith('file-size');
    expect(mockSendAllSettings).toHaveBeenCalled();
    expect(mockRefreshGraph).toHaveBeenCalled();
  });

  it('works with UndoManager execute → undo → redo', async () => {
    const undoManager = getUndoManager();
    const action = createAction();

    await undoManager.execute(action);
    expect(mockSetNodeSizeMode).toHaveBeenCalledWith('connections');

    vi.clearAllMocks();
    wireConfigMocks();

    const undoDesc = await undoManager.undo();
    expect(undoDesc).toBe('Reset all settings');
    expect(mockSetNodeSizeMode).toHaveBeenCalledWith('file-size');

    vi.clearAllMocks();
    wireConfigMocks();

    const redoDesc = await undoManager.redo();
    expect(redoDesc).toBe('Reset all settings');
    expect(mockSetNodeSizeMode).toHaveBeenCalledWith('connections');
  });
});

import { describe, it, expect, vi, beforeEach } from 'vitest';
import * as vscode from 'vscode';
import { DeleteFilesAction } from '../../../src/extension/actions/deleteFiles';

vi.mock('vscode', () => ({
  workspace: {
    fs: {
      readFile: vi.fn(),
      writeFile: vi.fn().mockResolvedValue(undefined),
      delete: vi.fn().mockResolvedValue(undefined),
    },
    getConfiguration: vi.fn(),
  },
  window: {
    showErrorMessage: vi.fn(),
  },
  Uri: {
    joinPath: vi.fn((base: { fsPath: string }, ...pathSegments: string[]) => ({
      fsPath: `${base.fsPath}/${pathSegments.join('/')}`,
      toString: () => `file://${base.fsPath}/${pathSegments.join('/')}`,
    })),
  },
  ConfigurationTarget: {
    Global: 1,
    Workspace: 2,
    WorkspaceFolder: 3,
  },
}));

describe('DeleteFilesAction', () => {
  const mockWorkspaceFolder = { fsPath: '/workspace' } as vscode.Uri;
  let mockRefreshGraph: ReturnType<typeof vi.fn>;
  let mockConfigUpdate: ReturnType<typeof vi.fn>;
  let currentFavorites: string[];

  beforeEach(() => {
    vi.clearAllMocks();
    mockRefreshGraph = vi.fn().mockResolvedValue(undefined);
    currentFavorites = [];

    vi.mocked(vscode.workspace.fs.readFile).mockResolvedValue(
      new Uint8Array([72, 101, 108, 108, 111])
    );
    vi.mocked(vscode.workspace.fs.delete).mockResolvedValue(undefined);
    vi.mocked(vscode.workspace.fs.writeFile).mockResolvedValue(undefined);

    mockConfigUpdate = vi.fn().mockResolvedValue(undefined);
    vi.mocked(vscode.workspace.getConfiguration).mockReturnValue({
      get: vi.fn((key: string, defaultValue: unknown) => {
        if (key === 'favorites') return [...currentFavorites];
        return defaultValue;
      }),
      update: mockConfigUpdate,
    } as unknown as vscode.WorkspaceConfiguration);
  });

  describe('description', () => {
    it('describes a single file deletion using the filename', () => {
      const action = new DeleteFilesAction(['src/utils/helper.ts'], mockWorkspaceFolder, mockRefreshGraph);
      expect(action.description).toBe('Delete: helper.ts');
    });

    it('describes multiple file deletions with a count', () => {
      const action = new DeleteFilesAction(['a.ts', 'b.ts', 'c.ts'], mockWorkspaceFolder, mockRefreshGraph);
      expect(action.description).toBe('Delete 3 files');
    });

    it('describes two file deletions with a count', () => {
      const action = new DeleteFilesAction(['a.ts', 'b.ts'], mockWorkspaceFolder, mockRefreshGraph);
      expect(action.description).toBe('Delete 2 files');
    });
  });

  describe('execute', () => {
    it('reads file contents before deletion for backup', async () => {
      const action = new DeleteFilesAction(['src/app.ts'], mockWorkspaceFolder, mockRefreshGraph);

      await action.execute();

      expect(vscode.workspace.fs.readFile).toHaveBeenCalledOnce();
      expect(vscode.workspace.fs.delete).toHaveBeenCalledWith(
        expect.objectContaining({ fsPath: '/workspace/src/app.ts' }),
        { useTrash: true }
      );
    });

    it('handles multiple files', async () => {
      const action = new DeleteFilesAction(
        ['src/a.ts', 'src/b.ts', 'src/c.ts'],
        mockWorkspaceFolder,
        mockRefreshGraph
      );

      await action.execute();

      expect(vscode.workspace.fs.readFile).toHaveBeenCalledTimes(3);
      expect(vscode.workspace.fs.delete).toHaveBeenCalledTimes(3);
    });

    it('continues with other files when one read fails', async () => {
      vi.mocked(vscode.workspace.fs.readFile)
        .mockRejectedValueOnce(new Error('not found'))
        .mockResolvedValueOnce(new Uint8Array([1, 2, 3]));

      const action = new DeleteFilesAction(
        ['missing.ts', 'exists.ts'],
        mockWorkspaceFolder,
        mockRefreshGraph
      );

      await action.execute();

      // Should still refresh graph even if one file failed
      expect(mockRefreshGraph).toHaveBeenCalledOnce();
    });

    it('removes deleted files from favorites', async () => {
      currentFavorites = ['src/app.ts', 'src/other.ts'];

      const action = new DeleteFilesAction(['src/app.ts'], mockWorkspaceFolder, mockRefreshGraph);

      await action.execute();

      expect(mockConfigUpdate).toHaveBeenCalledWith(
        'favorites',
        ['src/other.ts'],
        undefined,
      );
    });

