import { describe, it, expect, vi, beforeEach } from 'vitest';
import * as vscode from 'vscode';
import { ResetSettingsAction } from '../../../src/extension/actions/resetSettings';
import type { ISettingsSnapshot } from '../../../src/shared/settings/snapshot';

vi.mock('vscode', () => ({
  workspace: {
    getConfiguration: vi.fn(),
  },
  ConfigurationTarget: {
    Global: 1,
    Workspace: 2,
    WorkspaceFolder: 3,
  },
}));

function createMockConfig(store: Record<string, unknown>) {
  return {
    get: vi.fn(<T>(key: string, defaultValue?: T): T => {
      return (key in store ? store[key] : defaultValue) as T;
    }),
    update: vi.fn(async (key: string, value: unknown) => {
      if (value === undefined) {
        delete store[key];
      } else {
        store[key] = value;
      }
    }),
  } as unknown as vscode.WorkspaceConfiguration;
}

function createMockContext() {
  const state: Record<string, unknown> = {};
  return {
    workspaceState: {
      get: vi.fn(<T>(key: string, defaultValue?: T): T => {
        return (key in state ? state[key] : defaultValue) as T;
      }),
      update: vi.fn(async (key: string, value: unknown) => {
        state[key] = value;
      }),
    },
  } as unknown as vscode.ExtensionContext;
}

describe('ResetSettingsAction (config section mutant coverage)', () => {
  const SNAPSHOT: ISettingsSnapshot = {
    physics: { repelForce: 10, linkDistance: 100, linkForce: 0.2, damping: 0.5, centerForce: 0.3 },
    legends: [],
    filterPatterns: [],
    showOrphans: true,
    bidirectionalMode: 'separate',
    directionMode: 'arrows',
    directionColor: '#000000',
    nodeColors: { file: '#111111', folder: '#222222' },
    nodeVisibility: { file: true, folder: false },
    edgeVisibility: { imports: true, calls: false },
    edgeColors: { imports: '#333333', calls: '#444444' },
    pluginOrder: ['codegraphy.markdown'],
    disabledPlugins: ['codegraphy.python'],
    particleSpeed: 0.001,
    particleSize: 4,
    showLabels: true,
    maxFiles: 500,
    nodeSizeMode: 'connections',
  };

  let settingsStore: Record<string, unknown>;
  let mockConfig: vscode.WorkspaceConfiguration;

  beforeEach(() => {
    vi.clearAllMocks();
    settingsStore = {
      'physics.repelForce': SNAPSHOT.physics.repelForce,
      'physics.linkDistance': SNAPSHOT.physics.linkDistance,
      'physics.linkForce': SNAPSHOT.physics.linkForce,
      'physics.damping': SNAPSHOT.physics.damping,
      'physics.centerForce': SNAPSHOT.physics.centerForce,
      legend: [],
      filterPatterns: [],
      showOrphans: true,
      bidirectionalEdges: 'separate',
      directionMode: 'arrows',
      directionColor: '#000000',
      nodeColors: { file: '#111111', folder: '#222222' },
      nodeVisibility: { file: true, folder: false },
      edgeVisibility: { imports: true, calls: false },
      edgeColors: { imports: '#333333', calls: '#444444' },
      pluginOrder: ['codegraphy.markdown'],
      disabledPlugins: ['codegraphy.python'],
      particleSpeed: 0.001,
      particleSize: 4,
      showLabels: true,
      maxFiles: 500,
      nodeSizeMode: 'connections',
    };
    mockConfig = createMockConfig(settingsStore);
    vi.mocked(vscode.workspace.getConfiguration).mockReturnValue(mockConfig);
  });

  it('resets physics keys through the repo-local config during execute', async () => {
    const action = new ResetSettingsAction(
      SNAPSHOT,
      vscode.ConfigurationTarget.Workspace,
      createMockContext(),
      vi.fn(),
      vi.fn(),
      vi.fn().mockResolvedValue(undefined),
    );

    await action.execute();

    const calls = (mockConfig.update as ReturnType<typeof vi.fn>).mock.calls
      .filter(([key]) => String(key).startsWith('physics.'));
    expect(calls.map(call => call[0])).toEqual([
      'physics.repelForce',
      'physics.linkDistance',
      'physics.linkForce',
      'physics.damping',
      'physics.centerForce',
    ]);
    for (const call of calls) {
      expect(call[1]).toBeUndefined();
    }
  });

  it('resets non-physics keys through the same repo-local config during execute', async () => {
    const action = new ResetSettingsAction(
      SNAPSHOT,
      vscode.ConfigurationTarget.Workspace,
      createMockContext(),
      vi.fn(),
      vi.fn(),
      vi.fn().mockResolvedValue(undefined),
    );

    await action.execute();

    const calls = (mockConfig.update as ReturnType<typeof vi.fn>).mock.calls
      .filter(([key]) => !String(key).startsWith('physics.'));
    const keys = calls.map(call => call[0]);
    expect(keys).toContain('legend');
    expect(keys).toContain('showOrphans');
    expect(keys).toContain('bidirectionalEdges');
    expect(keys).toContain('nodeColors');
    expect(keys).toContain('nodeVisibility');
    expect(keys).toContain('edgeVisibility');
    expect(keys).toContain('edgeColors');
    expect(keys).toContain('pluginOrder');
    expect(keys).toContain('disabledPlugins');
    expect(keys).toContain('nodeSizeMode');
    for (const call of calls) {
      if (call[0] === 'nodeSizeMode') {
        expect(call[1]).toBe('connections');
        continue;
      }

      expect(call[1]).toBeUndefined();
    }
  });

  it('restores physics values through the repo-local config during undo', async () => {
    const action = new ResetSettingsAction(
      SNAPSHOT,
      vscode.ConfigurationTarget.Workspace,
      createMockContext(),
      vi.fn(),
      vi.fn(),
      vi.fn().mockResolvedValue(undefined),
    );

    await action.execute();
    (mockConfig.update as ReturnType<typeof vi.fn>).mockClear();

    await action.undo();

    const calls = (mockConfig.update as ReturnType<typeof vi.fn>).mock.calls
      .filter(([key]) => String(key).startsWith('physics.'));
    expect(calls.map(call => call[0])).toContain('physics.repelForce');
    expect(calls.map(call => call[0])).toContain('physics.damping');
    expect(calls.some(call => call[1] === SNAPSHOT.physics.repelForce)).toBe(true);
    expect(calls.some(call => call[1] === SNAPSHOT.physics.damping)).toBe(true);
  });

  it('updates repo settings without a VS Code target in execute and undo', async () => {
    const action = new ResetSettingsAction(
      SNAPSHOT,
      vscode.ConfigurationTarget.Workspace,
      createMockContext(),
      vi.fn(),
      vi.fn(),
      vi.fn().mockResolvedValue(undefined),
    );

    await action.execute();
    let calls = (mockConfig.update as ReturnType<typeof vi.fn>).mock.calls;
    expect(calls.every(call => call[2] === undefined)).toBe(true);

    (mockConfig.update as ReturnType<typeof vi.fn>).mockClear();
    await action.undo();
    calls = (mockConfig.update as ReturnType<typeof vi.fn>).mock.calls;
    expect(calls.every(call => call[2] === undefined)).toBe(true);
  });
});

import { describe, it, expect, vi, beforeEach } from 'vitest';
import * as vscode from 'vscode';
import { AddToExcludeAction } from '../../../src/extension/actions/addToExclude';

vi.mock('vscode', () => ({
  workspace: {
    getConfiguration: vi.fn(),
  },
  ConfigurationTarget: {
    Global: 1,
    Workspace: 2,
    WorkspaceFolder: 3,
  },
}));

function getLastFilterPatternUpdate(
  calls: Array<[string, unknown, unknown?]>,
): unknown {
  return [...calls]
    .reverse()
    .find(([key]) => key === 'filterPatterns')?.[1];
}

describe('AddToExcludeAction', () => {
  let mockConfigUpdate: ReturnType<typeof vi.fn>;
  let currentFilterPatterns: string[];
  let mockRefreshGraph: ReturnType<typeof vi.fn>;

  beforeEach(() => {
    vi.clearAllMocks();
    currentFilterPatterns = [];
    mockConfigUpdate = vi.fn().mockResolvedValue(undefined);

    vi.mocked(vscode.workspace.getConfiguration).mockReturnValue({
      get: vi.fn((key: string, defaultValue: unknown) => {
        if (key === 'filterPatterns') return [...currentFilterPatterns];
        return defaultValue;
      }),
      update: mockConfigUpdate,
    } as unknown as vscode.WorkspaceConfiguration);

    mockRefreshGraph = vi.fn().mockResolvedValue(undefined);
  });

  describe('description', () => {
    it('describes a single file exclusion using the filename', () => {
      const action = new AddToExcludeAction(['src/utils/helper.ts'], mockRefreshGraph);
      expect(action.description).toBe('Exclude: helper.ts');
    });

    it('describes multiple file exclusions with a count', () => {
      const action = new AddToExcludeAction(['a.ts', 'b.ts', 'c.ts'], mockRefreshGraph);
      expect(action.description).toBe('Exclude 3 files');
    });

    it('describes two file exclusions with a count', () => {
      const action = new AddToExcludeAction(['a.ts', 'b.ts'], mockRefreshGraph);
      expect(action.description).toBe('Exclude 2 files');
    });
  });

  describe('execute', () => {
    it('adds glob patterns to the filter pattern list', async () => {
      const action = new AddToExcludeAction(['src/app.ts'], mockRefreshGraph);

      await action.execute();

      expect(mockConfigUpdate).toHaveBeenCalledWith(
        'filterPatterns',
        ['**/src/app.ts'],
        undefined,
      );
    });

    it('preserves existing filter patterns', async () => {
      currentFilterPatterns = ['**/node_modules/**'];
      const action = new AddToExcludeAction(['dist/bundle.js'], mockRefreshGraph);

      await action.execute();

      expect(mockConfigUpdate).toHaveBeenCalledWith(
        'filterPatterns',
        expect.arrayContaining(['**/node_modules/**', '**/dist/bundle.js']),
        undefined,
      );
    });

    it('does not add duplicate patterns', async () => {
      currentFilterPatterns = ['**/src/app.ts'];
      const action = new AddToExcludeAction(['src/app.ts'], mockRefreshGraph);

      await action.execute();

      const updateArg = mockConfigUpdate.mock.calls.find(
        ([key]) => key === 'filterPatterns',
      )?.[1] as string[];
      const matchCount = updateArg.filter((pat) => pat === '**/src/app.ts').length;
      expect(matchCount).toBe(1);
    });

    it('adds multiple paths in a single execute', async () => {
      const action = new AddToExcludeAction(['a.ts', 'b.ts'], mockRefreshGraph);

      await action.execute();

      const updateArg = mockConfigUpdate.mock.calls.find(
        ([key]) => key === 'filterPatterns',
      )?.[1] as string[];
      expect(updateArg).toContain('**/a.ts');
      expect(updateArg).toContain('**/b.ts');
    });

    it('calls refreshGraph after updating config', async () => {
      const action = new AddToExcludeAction(['app.ts'], mockRefreshGraph);

      await action.execute();

      expect(mockRefreshGraph).toHaveBeenCalledOnce();
    });

    it('captures the before state only on first execution', async () => {
      const action = new AddToExcludeAction(['app.ts'], mockRefreshGraph);

      await action.execute();

      // Simulate external modification of the filter pattern list
      currentFilterPatterns = ['**/app.ts', '**/extra.ts'];

      // Re-execute (redo) should apply the same after state, not recalculate
      await action.execute();

      // The second call should use the same stateAfter from the first execution
      const filterPatternUpdates = mockConfigUpdate.mock.calls
        .filter(([key]) => key === 'filterPatterns')
        .map(([, value]) => value);
      const firstCallArg = filterPatternUpdates[0];
      const secondCallArg = filterPatternUpdates[1];
      expect(secondCallArg).toEqual(firstCallArg);
    });
  });

  describe('undo', () => {
    it('restores the filter pattern list to its state before execute', async () => {
      currentFilterPatterns = ['**/existing.ts'];
      const action = new AddToExcludeAction(['new.ts'], mockRefreshGraph);

      await action.execute();
      await action.undo();

      // The undo should restore to ['**/existing.ts']
      const undoCallArg = getLastFilterPatternUpdate(
        mockConfigUpdate.mock.calls as Array<[string, unknown, unknown?]>,
      );
      expect(undoCallArg).toEqual(['**/existing.ts']);
    });

    it('restores to empty array when the list was originally empty', async () => {
      const action = new AddToExcludeAction(['app.ts'], mockRefreshGraph);

      await action.execute();
      await action.undo();

      const undoCallArg = getLastFilterPatternUpdate(
        mockConfigUpdate.mock.calls as Array<[string, unknown, unknown?]>,
      );
      expect(undoCallArg).toEqual([]);
    });

    it('calls refreshGraph after restoring', async () => {
      const action = new AddToExcludeAction(['app.ts'], mockRefreshGraph);

      await action.execute();
      vi.clearAllMocks();
      await action.undo();

      expect(mockRefreshGraph).toHaveBeenCalledOnce();
    });
  });

  describe('execute after undo (redo)', () => {
    it('reapplies the same after state on redo', async () => {
      const action = new AddToExcludeAction(['app.ts'], mockRefreshGraph);

      await action.execute();
      const firstAfter = mockConfigUpdate.mock.calls.find(
        ([key]) => key === 'filterPatterns',
      )?.[1];

      await action.undo();
      await action.execute();

      const redoAfter = mockConfigUpdate.mock.calls
        .filter(([key]) => key === 'filterPatterns')
        .at(-1)?.[1];
      expect(redoAfter).toEqual(firstAfter);
    });
  });
});

/**
 * @fileoverview Additional tests for AddToExcludeAction targeting surviving mutants.
 *
 * Surviving mutants:
 * - L18:36, L20:35 ArrayDeclaration: initial _stateBefore/_stateAfter = []
 * - L39:54 StringLiteral: config section 'codegraphy'
 * - L40:60 ArrayDeclaration: default [] in config.get('filterPatterns', [])
 * - L62:54 StringLiteral: config section 'codegraphy' in undo
 * - L65:25 StringLiteral: pattern prefix in undo path
 */

import { describe, it, expect, vi, beforeEach } from 'vitest';
import * as vscode from 'vscode';
